'use client'
import { useSignal, useSignals } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import styles from './steps.module.css'

export type StepState = 'pending' | 'active' | 'complete' | 'error'

export interface Step {
  label: string
  state?: StepState
}

export interface StepsProps {
  steps: Step[]
  activeStep?: number
  orientation?: 'horizontal' | 'vertical'
  className?: string
  /** Accessible label for the steps list */
  ariaLabel?: string
}

export function Steps({
  steps,
  activeStep: controlledActiveStep,
  orientation = 'horizontal',
  className,
  ariaLabel,
}: StepsProps) {
  useSignals()
  const active = useSignal(controlledActiveStep ?? 0)
  active.value = controlledActiveStep ?? active.value
  const resolvedAriaLabel = ariaLabel ?? t(builtin.steps.label)

  return (
    <ol
      className={[styles.steps, className].filter(Boolean).join(' ')}
      data-orientation={orientation}
      aria-label={resolvedAriaLabel}
    >
      {steps.map((step, i) => {
        const state: StepState =
          step.state ?? (i < active.value ? 'complete' : i === active.value ? 'active' : 'pending')
        return (
          <li
            key={i}
            className={styles.step}
            data-state={state}
            aria-current={state === 'active' ? 'step' : undefined}
          >
            <div className={styles.circle}>
              {state === 'complete' ? '✓' : state === 'error' ? '✕' : i + 1}
            </div>
            <span className={styles.label}>{step.label}</span>
          </li>
        )
      })}
    </ol>
  )
}

@layer cascivo.component {
  .steps {
    display: flex;
    gap: 0;
    list-style: none;
    margin: 0;
    padding: 0;
  }

  .steps[data-orientation='horizontal'] {
    flex-direction: row;
    align-items: center;
  }
  .steps[data-orientation='vertical'] {
    flex-direction: column;
  }

  .step {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    flex: 1;
    position: relative;
  }

  .step:not(:last-child)::after {
    content: '';
    flex: 1;
    block-size: 1px;
    background-color: var(--cascivo-border-default);
  }

  .steps[data-orientation='vertical'] .step:not(:last-child)::after {
    position: absolute;
    inset-inline-start: 0.75rem;
    inset-block-start: 2rem;
    inline-size: 1px;
    block-size: calc(100% - 1.5rem);
    flex: none;
  }

  .circle {
    display: flex;
    align-items: center;
    justify-content: center;
    inline-size: 1.5rem;
    block-size: 1.5rem;
    border-radius: var(--cascivo-radius-full);
    border: 2px solid var(--cascivo-border-default);
    background-color: var(--cascivo-color-surface);
    font-size: 0.75rem;
    font-weight: 600;
    color: var(--cascivo-color-text-muted);
    flex-shrink: 0;
    transition:
      background-color 150ms var(--cascivo-ease-out),
      border-color 150ms var(--cascivo-ease-out);
  }

  .step[data-state='active'] .circle {
    background-color: var(--cascivo-color-accent);
    border-color: var(--cascivo-color-accent);
    color: var(--cascivo-color-accent-content);
  }

  .step[data-state='complete'] .circle {
    background-color: var(--cascivo-color-success);
    border-color: var(--cascivo-color-success);
    color: var(--cascivo-color-success-content);
  }

  .step[data-state='error'] .circle {
    background-color: var(--cascivo-color-error);
    border-color: var(--cascivo-color-error);
    color: var(--cascivo-color-error-content);
  }

  .step[data-state='complete']:not(:last-child)::after {
    background-color: var(--cascivo-color-success);
  }

  .label {
    font-size: 0.875rem;
    color: var(--cascivo-color-text-subtle);
  }

  .step[data-state='active'] .label {
    color: var(--cascivo-color-text);
    font-weight: 500;
  }
  .step[data-state='complete'] .label {
    color: var(--cascivo-color-text-subtle);
  }
  .step[data-state='error'] .label {
    color: var(--cascivo-color-error);
  }
}
